def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        if item < 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        penalty_accum = 0.0
        boost = 1.0
        if item == 0:
            priorities[i] = 0
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for k in range(1, 10):
                penalty_accum += (ratio ** (2 * k)) / (np.sqrt(k) + 1)
            for j in range(1, 6):
                decay *= (1 - 1 / (ratio + j**1.5 + 3))
            score = (ratio ** 6) / 5 + penalty_accum
            if item > capacity * 7:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 5:
            temp = 0
            for x in range(1, 15):
                sign = (-1) ** (x + 1)
                temp += sign * (ratio ** x) / (x + 1) ** 1.2
            for y in range(1, 8):
                decay *= (1 - 1 / (ratio + y + 2))
            score = abs(temp) * decay * 15
            if item < capacity * 4:
                boost = 1.2
            else:
                boost = 0.85
            priorities[i] = score * boost
        elif 1.5 < ratio <= 3:
            temp = 0
            for p in range(1, 20):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 4)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 20 if ratio < 2 else 12 if ratio < 2.5 else 7
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0
                for m in range(1, 10):
                    extra += (ratio ** m) / (m + 4)
                score += extra * 3
            priorities[i] = score
        elif 0.5 < ratio <= 1.5:
            temp_score = 0
            for p in range(1, 25):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 3)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 5)
                else:
                    temp_score -= (ratio ** p) / (p * 7)
            if ratio < 0.7:
                multiplier = 18
            elif ratio < 1.0:
                multiplier = 10
            else:
                multiplier = 6
            score = abs(temp_score) * multiplier
            if 1.3 < ratio <= 1.5:
                extra_penalty = 0
                for n in range(1, 12):
                    extra_penalty += (ratio ** n) / (n + 2)
                score += extra_penalty * 4
            priorities[i] = score
        elif 0 < ratio <= 0.5:
            temp_score = 0
            for p in range(1, 30):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 5)
                else:
                    temp_score += (ratio ** p) / (p * 6)
            if ratio < 0.1:
                multiplier = 40
            elif ratio < 0.3:
                multiplier = 30
            elif ratio < 0.4:
                multiplier = 20
            else:
                multiplier = 12
            score = abs(temp_score) * multiplier
            if ratio > 0.4:
                extra_penalty = 0
                for n in range(1, 15):
                    extra_penalty += (ratio ** n) / (n + 3)
                score += extra_penalty * 5
            priorities[i] = score
        else:
            priorities[i] = np.inf
        if priorities[i] != np.inf and capacity > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z ** 1.1 / (capacity + z))
            priorities[i] *= factor
        elif capacity <= 0:
            priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf:
            mod = 1
            for q in range(i % 3 + 1):
                mod += ((-1) ** q) * (item + bins[i]) / (q + 2)
            priorities[i] *= mod if mod > 0 else 1
    return priorities
